// Custom debounce hook: returns the debounced value plus a flag that is
// true while a new value is "pending" (i.e. during the debounce delay).
function useDebouncedValue(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);
    const [isPending, setIsPending] = useState(false);

    useEffect(() => {
        // If the incoming value already matches, nothing is pending.
        if (value === debouncedValue) {
            setIsPending(false);
            return;
        }

        setIsPending(true);
        const timeoutId = setTimeout(() => {
            setDebouncedValue(value);
            setIsPending(false);
        }, delay);

        // Cleanup clears the timeout on value change OR unmount,
        // preventing stale updates and memory leaks.
        return () => clearTimeout(timeoutId);
